class VotingMachine:
    def __init__(self):
        self.votes = {}

    def add_candidate(self, name):
        if name not in self.votes:
            self.votes[name] = 0

    def cast_vote(self, name):
        if name in self.votes:
            self.votes[name] += 1
        else:
            print("Candidate not found.")

    def remove_vote(self, name):
        if name in self.votes:
            self.votes[name] -= 1
            if self.votes[name] < 0:
                self.votes[name] = 0
        else:
            print("Candidate not found.")

    def get_votes(self, name):
        if name in self.votes:
            return self.votes[name]
        else:
            return 0

    def print_results(self):
        for name, votes in self.votes.items():
            print(f"{name}: {votes}")


# Example usage:
voting_machine = VotingMachine()

# Add candidates
voting_machine.add_candidate("John")
